def all_anagram_start_indices(pattern: str, s: str):
    from collections import Counter
    m = len(pattern)
    res = []
    if m > len(s):
        return res
    need = Counter(pattern)
    have = Counter(s[:m])
    if have == need:
        res.append(0)
    for i in range(m, len(s)):
        have[s[i]] += 1
        left_char = s[i - m]
        have[left_char] -= 1
        if have[left_char] == 0:
            del have[left_char]
        if have == need:
            res.append(i - m + 1)
    return res

